INSERT INTO public.posts (title, slug, type, content, content_html, is_published, published_at, view_count)
VALUES (
  'What are NFTs?',
  'what-are-nfts',
  'guide',
  '{"html": "<h2>Non-Fungible Tokens Explained</h2><p><strong>NFTs (Non-Fungible Tokens)</strong> are unique digital assets that represent ownership of specific items on the blockchain.</p><h3>Fungible vs Non-Fungible</h3><p><strong>Fungible:</strong> Interchangeable and identical. One dollar equals another dollar; one Bitcoin equals another Bitcoin.</p><p><strong>Non-Fungible:</strong> Unique and not interchangeable. Like houses, artwork, or collectibles—each has distinct characteristics and value.</p><h3>How NFTs Work</h3><p>NFTs are smart contracts on blockchains (primarily Ethereum) that contain:</p><ul><li>Unique identifier (token ID)</li><li>Metadata (name, description, properties)</li><li>Link to digital content (image, video, audio)</li><li>Ownership and transaction history</li></ul><h3>Popular NFT Categories</h3><p><strong>Digital Art:</strong> Unique artwork by digital artists, sold on platforms like OpenSea and Foundation.</p><p><strong>Profile Pictures (PFPs):</strong> Collections like Bored Ape Yacht Club and CryptoPunks.</p><p><strong>Gaming Assets:</strong> In-game items, characters, and virtual land.</p><p><strong>Music:</strong> Songs, albums, and exclusive content from artists.</p><p><strong>Domain Names:</strong> Blockchain domains like .eth names.</p><p><strong>Collectibles:</strong> Digital trading cards, sports moments, and memorabilia.</p><h3>Why NFTs Have Value</h3><ul><li><strong>Scarcity:</strong> Limited supply creates demand</li><li><strong>Provenance:</strong> Verifiable ownership history</li><li><strong>Utility:</strong> Access to communities, events, or services</li><li><strong>Cultural significance:</strong> Part of internet culture</li><li><strong>Investment potential:</strong> Some appreciate significantly</li></ul><h3>Creating and Minting NFTs</h3><ol><li>Create digital content</li><li>Choose a blockchain (Ethereum, Polygon, Solana)</li><li>Set up a crypto wallet</li><li>Connect to an NFT marketplace</li><li>Upload your content</li><li>Add metadata and properties</li><li>Mint your NFT (pay gas fees)</li><li>List for sale or auction</li></ol><h3>Buying NFTs</h3><ol><li>Set up and fund a crypto wallet</li><li>Connect to NFT marketplace</li><li>Browse or search for NFTs</li><li>Check collection details and rarity</li><li>Place a bid or buy instantly</li><li>Complete transaction in wallet</li><li>NFT appears in your wallet</li></ol><h3>Popular NFT Marketplaces</h3><ul><li><strong>OpenSea:</strong> Largest NFT marketplace</li><li><strong>Blur:</strong> Pro trader platform with lower fees</li><li><strong>Rarible:</strong> Community-owned marketplace</li><li><strong>Foundation:</strong> Curated art platform</li><li><strong>Magic Eden:</strong> Leading Solana NFT marketplace</li></ul><h3>Risks and Considerations</h3><ul><li>Market is highly speculative</li><li>Value can drop to zero</li><li>Smart contract vulnerabilities</li><li>Scams and fake collections</li><li>Copyright and IP issues</li><li>Environmental concerns (though improving)</li></ul><p>NFTs represent a new paradigm of digital ownership, enabling creators to monetize work directly and collectors to own verifiable unique items in the digital realm.</p>"}',
  '<h2>Non-Fungible Tokens Explained</h2><p><strong>NFTs (Non-Fungible Tokens)</strong> are unique digital assets that represent ownership of specific items on the blockchain.</p><h3>Fungible vs Non-Fungible</h3><p><strong>Fungible:</strong> Interchangeable and identical. One dollar equals another dollar; one Bitcoin equals another Bitcoin.</p><p><strong>Non-Fungible:</strong> Unique and not interchangeable. Like houses, artwork, or collectibles—each has distinct characteristics and value.</p><h3>How NFTs Work</h3><p>NFTs are smart contracts on blockchains (primarily Ethereum) that contain:</p><ul><li>Unique identifier (token ID)</li><li>Metadata (name, description, properties)</li><li>Link to digital content (image, video, audio)</li><li>Ownership and transaction history</li></ul><h3>Popular NFT Categories</h3><p><strong>Digital Art:</strong> Unique artwork by digital artists, sold on platforms like OpenSea and Foundation.</p><p><strong>Profile Pictures (PFPs):</strong> Collections like Bored Ape Yacht Club and CryptoPunks.</p><p><strong>Gaming Assets:</strong> In-game items, characters, and virtual land.</p><p><strong>Music:</strong> Songs, albums, and exclusive content from artists.</p><p><strong>Domain Names:</strong> Blockchain domains like .eth names.</p><p><strong>Collectibles:</strong> Digital trading cards, sports moments, and memorabilia.</p><h3>Why NFTs Have Value</h3><ul><li><strong>Scarcity:</strong> Limited supply creates demand</li><li><strong>Provenance:</strong> Verifiable ownership history</li><li><strong>Utility:</strong> Access to communities, events, or services</li><li><strong>Cultural significance:</strong> Part of internet culture</li><li><strong>Investment potential:</strong> Some appreciate significantly</li></ul><h3>Creating and Minting NFTs</h3><ol><li>Create digital content</li><li>Choose a blockchain (Ethereum, Polygon, Solana)</li><li>Set up a crypto wallet</li><li>Connect to an NFT marketplace</li><li>Upload your content</li><li>Add metadata and properties</li><li>Mint your NFT (pay gas fees)</li><li>List for sale or auction</li></ol><h3>Buying NFTs</h3><ol><li>Set up and fund a crypto wallet</li><li>Connect to NFT marketplace</li><li>Browse or search for NFTs</li><li>Check collection details and rarity</li><li>Place a bid or buy instantly</li><li>Complete transaction in wallet</li><li>NFT appears in your wallet</li></ol><h3>Popular NFT Marketplaces</h3><ul><li><strong>OpenSea:</strong> Largest NFT marketplace</li><li><strong>Blur:</strong> Pro trader platform with lower fees</li><li><strong>Rarible:</strong> Community-owned marketplace</li><li><strong>Foundation:</strong> Curated art platform</li><li><strong>Magic Eden:</strong> Leading Solana NFT marketplace</li></ul><h3>Risks and Considerations</h3><ul><li>Market is highly speculative</li><li>Value can drop to zero</li><li>Smart contract vulnerabilities</li><li>Scams and fake collections</li><li>Copyright and IP issues</li><li>Environmental concerns (though improving)</li></ul><p>NFTs represent a new paradigm of digital ownership, enabling creators to monetize work directly and collectors to own verifiable unique items in the digital realm.</p>',
  true,
  now(),
  0
);